refentry.refsect1:
  &reftitle.parameters;




     codepoint



       Un &integer; entre 0 et 255;



       Les valeurs en dehors de l'intervalle valide (0..255) seront
       converties en valeur positive, et se termineront à 255, ce qui est
       l'équivalent de l'algorithme suivant :


while ($bytevalue < 0) {
    $bytevalue += 256;
}
$bytevalue %= 256;

&reftitle.changelog;





    &Version;
    &Description;





    7.4.0

     Cette fonction n'accepte plus silencieusement les codepoints
     non supporté, et casts ces valeurs à 0.

  &reftitle.examples;



    Exemple avec chr


<?php
// Suppose que la chaîne sera utilisée en tant que ASCII ou un encodage
// compatible avec celui-ci

$str = "The string ends in escape: ";

// Ajoute un caractère d'échappement à la fin de la chaîne $str
$str .= chr(27);
echo $str, PHP_EOL;
// Ceci est souvent plus pratique, et réalise la même chose

$str = sprintf("The string ends in escape: %c", 27);
?>







    Comportement de débordement


<?php
echo chr(-159), chr(833), PHP_EOL;
?>


    &example.outputs;


aA







    Construire une chaîne UTF-8 à partir d'octets individuels


<?php
$str = chr(240) . chr(159) . chr(144) . chr(152);
echo $str, PHP_EOL;
?>


